package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreSurroundingSpaces() {
        // Create a CSVFormat instance for testing
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null,
                false, true, "\r\n", null, null, false, false);

        // Set up the parameters for the new CSVFormat
        char newDelimiter = ';';
        char newQuoteCharacter = '\'';
        QuoteMode newQuoteMode = QuoteMode.ALL;
        char newCommentMarker = '#';
        char newEscapeCharacter = '\\';
        boolean newIgnoreSurroundingSpaces = true;
        boolean newIgnoreEmptyLines = false;
        String newRecordSeparator = "\n";
        String newNullString = "NULL";
        String[] newHeader = {"Header1", "Header2"};
        boolean newSkipHeaderRecord = true;
        boolean newAllowMissingColumnNames = true;

        // Call the method to test
        CSVFormat newCsvFormat = csvFormat.withIgnoreSurroundingSpaces(newIgnoreSurroundingSpaces);

        // Use reflection to access private fields for comparison
        assertEquals(newDelimiter, newCsvFormat.getDelimiter());
        assertEquals(newQuoteCharacter, newCsvFormat.getQuoteCharacter());
        assertEquals(newQuoteMode, newCsvFormat.getQuoteMode());
        assertEquals(newCommentMarker, newCsvFormat.getCommentMarker());
        assertEquals(newEscapeCharacter, newCsvFormat.getEscapeCharacter());
        assertEquals(newIgnoreSurroundingSpaces, newCsvFormat.getIgnoreSurroundingSpaces());
        assertEquals(newIgnoreEmptyLines, newCsvFormat.getIgnoreEmptyLines());
        assertEquals(newRecordSeparator, newCsvFormat.getRecordSeparator());
        assertEquals(newNullString, newCsvFormat.getNullString());
        assertEquals(newHeader, newCsvFormat.getHeader());
        assertEquals(newSkipHeaderRecord, newCsvFormat.getSkipHeaderRecord());
        assertEquals(newAllowMissingColumnNames, newCsvFormat.getAllowMissingColumnNames());
    }
}
